"""Test generation for OaFn* operations from TOML schemas.
"""

from __future__ import annotations


def generate_test_file(ops: list[dict], schema_name: str, category: str, namespace: str = "OaFnMatrix") -> str:
    """Generate complete test file from schema with [ops.test] sections."""
    
    # Header
    lines = [
        "// AUTO-GENERATED by Tools/FnAutogen/oafnautogen.py — DO NOT EDIT.",
        f"// Source of truth: Tools/FnAutogen/Schema/{schema_name}.",
        "//",
        "// Tests for context-backed public overloads.",
        "// The public overload test doubles as the kernel correctness test —",
        "// it calls OaFnMatrix::<Op>(...) which dispatches the SPIR-V kernel directly.",
        "// CPU references come from each op's `forward_op` field.",
        "",
        "#include <gtest/gtest.h>",
        "#include <Oa/Core/FnMatrix.h>",
        "#include <Oa/Runtime/Engine.h>",
        "#include <Oa/Runtime/Context.h>",
        "#include <Oa/Runtime/ComputeGraph.h>",
        "#include <Oa/Runtime/RuntimeGlobal.h>",
        "#include <cmath>",
        "#include <vector>",
        "",
        "static OaComputeEngine* GRt = nullptr;",
        "",
        f"class Test{namespace}{category} : public ::testing::Test {{",
        "protected:",
        "\tstatic void SetUpTestSuite() {",
        "\t\tOaEngineConfig cfg{};",
        f"\t\tcfg.AppName = \"Test{namespace}{category}\";",
        "\t\tauto r = OaComputeEngine::Create(cfg);",
        "\t\tASSERT_TRUE(r.IsOk()) << r.GetStatus().GetMessage();",
        "\t\tstatic OaUniquePtr<OaComputeEngine> rt = std::move(*r);",
        "\t\tGRt = rt.get();",
        "\t\tOaRuntimeGlobal::SetRuntime(GRt);",
        "\t}",
        "};",
        "",
    ]
    
    # Generate tests for each op
    for op in ops:
        test_config = op.get("test")
        if not test_config:
            continue  # Skip ops without test config
        if test_config.get("skip_test", False):
            continue  # Skip ops marked with skip_test = true
        
        lines.extend(_generate_context_test(op, category, namespace, test_config))
        
        # Autograd removed - no longer generating backward tests
    
    return "\n".join(lines)


def _generate_context_test(op: dict, category: str, namespace: str, test_config: dict) -> list[str]:
    """Generate context-based correctness test with CPU reference."""
    name = op["name"]
    kind = op["kind"]
    cpu_ref = test_config.get("cpu_reference", "")
    tolerance = test_config.get("tolerance", "1e-4f")
    test_size = test_config.get("test_sizes", [256])[0]
    
    lines = [
        f"TEST_VK(Test{namespace}{category}, {name}_Context) {{",
        f"\tconstexpr OaU32 N = {test_size};",
    ]
    
    # Setup inputs based on kind
    if kind == "binary":
        lines.extend([
            "\tauto a = OaFnMatrix::Rand(OaMatrixShape{N});",
            "\tauto b = OaFnMatrix::Rand(OaMatrixShape{N});",
            "\tstd::vector<float> b_host(N);",
            "\tASSERT_TRUE(OaFnMatrix::CopyToHost(b, b_host.data(), N * sizeof(float)).IsOk());",
        ])
    elif kind == "unary":
        lines.extend([
            "\tauto a = OaFnMatrix::Rand(OaMatrixShape{N});",
        ])
    elif kind == "reduce_full":
        lines.extend([
            "\tauto a = OaFnMatrix::Rand(OaMatrixShape{N});",
        ])
    elif kind == "unary_scalar":
        scalar_value = test_config.get("scalar_value", "1.5f")
        lines.extend([
            f"\tconstexpr OaF32 kScalar = {scalar_value};",
            "\tauto a = OaFnMatrix::Rand(OaMatrixShape{N});",
        ])
    
    # Execute operation
    lines.append("\tOaContext::Scope ctx_scope(OaContext::GetDefault());")
    
    if kind == "binary":
        lines.append(f"\tauto out = OaFnMatrix::{name}(a, b);")
    elif kind == "unary":
        lines.append(f"\tauto out = OaFnMatrix::{name}(a);")
    elif kind == "reduce_full":
        lines.append(f"\tauto out = OaFnMatrix::{name}(a);")
    elif kind == "unary_scalar":
        lines.append(f"\tauto out = OaFnMatrix::{name}(a, kScalar);")
    
    lines.append("\t// Context scope auto-executes and syncs at end of scope")
    
    # CPU reference validation
    if kind == "reduce_full":
        # Reduce operations return a scalar
        lines.extend([
            "\tstd::vector<float> a_host(N);",
            "\tASSERT_TRUE(OaFnMatrix::CopyToHost(a, a_host.data(), N * sizeof(float)).IsOk());",
            f"\tfloat want = {cpu_ref};",
            "\tfloat got = 0.0f;",
            "\tASSERT_TRUE(OaFnMatrix::CopyToHost(out, &got, sizeof(float)).IsOk());",
            f"\tEXPECT_NEAR(got, want, {tolerance}) << \"Reduction result mismatch\";",
            "}",
            "",
        ])
    else:
        # Element-wise operations
        lines.extend([
            "\tstd::vector<float> a_host(N);",
            "\tASSERT_TRUE(OaFnMatrix::CopyToHost(a, a_host.data(), N * sizeof(float)).IsOk());",
            "\tstd::vector<float> want(N);",
            f"\tfor (OaU32 i = 0; i < N; ++i) want[i] = {cpu_ref};",
            "\tstd::vector<float> got(N);",
            "\tASSERT_TRUE(OaFnMatrix::CopyToHost(out, got.data(), N * sizeof(float)).IsOk());",
            f"\tfor (OaU32 i = 0; i < N; ++i) EXPECT_NEAR(got[i], want[i], {tolerance}) << \"i=\" << i;",
            "}",
            "",
        ])
    
    return lines


def _generate_backward_test(op: dict, category: str, namespace: str) -> list[str]:
    """Generate backward/gradient test for differentiable ops."""
    name = op["name"]
    kind = op["kind"]
    autograd = op.get("autograd", {})
    differentiable = autograd.get("differentiable", [])
    
    lines = [
        f"TEST_VK(Test{namespace}{category}, {name}_Backward) {{",
    ]
    
    # Setup inputs
    if kind == "binary":
        lines.extend([
            "\tauto a = OaFnMatrix::Full(OaMatrixShape{8}, 2.0f);",
            "\tauto b = OaFnMatrix::Full(OaMatrixShape{8}, 3.0f);",
            "\ta.SetRequiresGrad(true);",
            "\tb.SetRequiresGrad(true);",
            f"\tauto c = OaFnMatrix::Sum(OaFnMatrix::{name}(a, b));",
        ])
    elif kind == "unary":
        lines.extend([
            "\tauto a = OaFnMatrix::Full(OaMatrixShape{8}, 2.0f);",
            "\ta.SetRequiresGrad(true);",
            f"\tauto c = OaFnMatrix::Sum(OaFnMatrix::{name}(a));",
        ])
    elif kind == "unary_scalar":
        test_config = op.get("test", {})
        scalar_value = test_config.get("scalar_value", "1.5f")
        lines.extend([
            "\tauto a = OaFnMatrix::Full(OaMatrixShape{8}, 2.0f);",
            "\ta.SetRequiresGrad(true);",
            f"\tconstexpr OaF32 kScalar = {scalar_value};",
            f"\tauto c = OaFnMatrix::Sum(OaFnMatrix::{name}(a, kScalar));",
        ])
    
    # Backward pass
    lines.append("\tc.Backward();")
    
    # Assertions
    if "A" in differentiable:
        lines.append("\tEXPECT_TRUE(a.HasGrad()) << \"A should have grad after backward\";")
    if "B" in differentiable:
        lines.append("\tEXPECT_TRUE(b.HasGrad()) << \"B should have grad after backward\";")
    
    lines.extend([
        "}",
        "",
    ])
    
    return lines
